import json
import boto3
from botocore.exceptions import NoCredentialsError, PartialCredentialsError

# IAM role definition: 
"""
{
    "Version": "2012-10-17",
    "Statement": [
        {
            "Effect": "Allow",
            "Action": [
                "s3:GetObject",
                "s3:PutObject",
                "sns:Publish"
            ],
            "Resource": [
                "arn:aws:s3:::your_bucket_name/*",
                "arn:aws:sns:us-east-1:account_id:topic_name"
            ]
        }
    ]
}
"""

def lambda_handler(event, context):
    s3 = boto3.resource('s3')
    client = boto3.client('sns', region_name='us-east-1')
    
    try:
        # Get the object from the event and show its content type
        bucket = s3.Bucket(event['Records'][0]['s3']['bucket']['name'])
        key = event['Records'][0]['s3']['object']['key'] 
        obj = s3.Object(bucket, key)
        
        # Process the image (this is where you would do your image processing)
        print("Processing " + key)
        
        # Save results to S3
        obj.put(Body='image_processing_results')  # Replace 'image_processing_results' with actual result data
        print('Image processing and saving done!')
        
        # Send notification via SNS
        response = client.publish(
            TopicArn='arn:aws:sns:us-east-1:account_id:topic_name',  # Replace with your topic ARN
            Message=f"Image processing and saving done for {key}",
            Subject='Image Processing Notification'
        )
        
    except (NoCredentialsError, PartialCredentialsError):
        print("No valid credentials found.")
    
    except Exception as e:
        print(f"An error occurred: {str(e)}")